impl.spec_text:
trait Tr1 { }
trait Tr2 { }

struct X<T> { a: T, b: T }

impl<T: Tr2> X<T> {
    #[verifier::external]
    fn swap(self) -> X<T>
        where T: Tr1
    {
        X { a: self.b, b: self.a }
    }
}

#[verifier::external_fn_specification]
fn ex_X_swap<T: Tr1 + Tr2>(x: X<T>) -> (res: X<T>)
      ensures res.a == x.b && res.b == x.a
{
    x.swap()
}

struct Foo(u8);
impl Tr1 for Foo { }
impl Tr2 for Foo { }

impl.impl_text:
fn test() {
    let z = X::<Foo> { a: Foo(5), b: Foo(7) };
    let w = z.swap();

    assert(w == X { a: Foo(7), b: Foo(5) });
}
